                    def __init__(
                        self,
                        scheme: Union[str, Scheme],
                        name: Optional[Union[str, Name]] = None,
                        in_: Optional[Union[str, In]] = None,
                        proxy: Optional[Union[str, Proxy]] = None,
                        id_short: Optional[str] = r"basic_sc",
                        display_name: Optional[
                            MultiLanguageNameType
                        ] = MultiLanguageNameType(dict_={r"en": r"Basic Sc"}),
                        category: Optional[str] = None,
                        description: Optional[
                            MultiLanguageTextType
                        ] = MultiLanguageTextType(
                            dict_={
                                r"en": r"This SubmodelElements holds the information about security mechanism based on basic security."
                            }
                        ),
                        semantic_id: Optional[Reference] = ExternalReference(
                            key=(
                                Key(
                                    type_=KeyTypes.GLOBAL_REFERENCE,
                                    value=r"https://www.w3.org/2019/wot/security#BasicSecurityScheme",
                                ),
                            ),
                            referred_semantic_id=None,
                        ),
                        qualifier: Iterable[Qualifier] = None,
                        extension: Iterable[Extension] = (),
                        supplemental_semantic_id: Iterable[Reference] = (),
                        embedded_data_specifications: Iterable[
                            EmbeddedDataSpecification
                        ] = None,
                    ):

                        if qualifier is None:
                            qualifier = (
                                Qualifier(
                                    type_=r"Cardinality",
                                    value_type=str,
                                    value=r"ZeroToOne",
                                    value_id=None,
                                    kind=QualifierKind.CONCEPT_QUALIFIER,
                                    semantic_id=None,
                                    supplemental_semantic_id=(),
                                ),
                            )

                        if embedded_data_specifications is None:
                            embedded_data_specifications = []

                        # Build a submodel element if a raw value was passed in the argument
                        if scheme and not isinstance(scheme, SubmodelElement):
                            scheme = self.Scheme(scheme)

                        # Build a submodel element if a raw value was passed in the argument
                        if name and not isinstance(name, SubmodelElement):
                            name = self.Name(name)

                        # Build a submodel element if a raw value was passed in the argument
                        if in_ and not isinstance(in_, SubmodelElement):
                            in_ = self.In(in_)

                        # Build a submodel element if a raw value was passed in the argument
                        if proxy and not isinstance(proxy, SubmodelElement):
                            proxy = self.Proxy(proxy)

                        # Add all passed/initialized submodel elements to a single list
                        embedded_submodel_elements = []
                        for se_arg in [scheme, name, in_, proxy]:
                            if se_arg is None:
                                continue
                            elif isinstance(se_arg, SubmodelElement):
                                embedded_submodel_elements.append(se_arg)
                            elif isinstance(se_arg, Iterable):
                                for n, element in enumerate(se_arg):
                                    element.id_short = f"{element.id_short}{n}"
                                    embedded_submodel_elements.append(element)
                            else:
                                raise TypeError(
                                    f"Unknown type of value in submodel_element_args: {type(se_arg)}"
                                )

                        super().__init__(
                            value=embedded_submodel_elements,
                            id_short=id_short,
                            display_name=display_name,
                            category=category,
                            description=description,
                            semantic_id=semantic_id,
                            qualifier=qualifier,
                            extension=extension,
                            supplemental_semantic_id=supplemental_semantic_id,
                            embedded_data_specifications=embedded_data_specifications,
                        )

